mapper.insert:
insert into `history` (
    session_id, user_id, username, role, content, trace_id,
    hit_count, refused, status, source_json, create_time, update_time
)
values (
    #{sessionId}, #{userId}, #{username}, #{role}, #{content}, #{traceId},
    #{hitCount}, #{refused}, #{status}, #{sourceJson}, #{createTime}, #{updateTime}
)

mapper.select:
select *
from `history`
where user_id = #{userId}
  and session_id = #{sessionId}
order by create_time asc, id asc

select *
from (
    select *
    from `history`
    where user_id = #{userId}
      and session_id = #{sessionId}
    order by create_time desc, id desc
    limit #{limit}
) recent
order by create_time asc, id asc

mapper.delete:
delete from `history`
where user_id = #{userId}
  and session_id = #{sessionId}
